solution:
INTERLIS 2.4;

MODEL BuildingKinds (de) AT "https://example.com" VERSION "2026-05-19" =
  TOPIC Data =
    DOMAIN BuildingName = TEXT*100;

    CLASS Building =
      Name : BuildingName;
      Usage : (residential, commercial, public);
    END Building;
  END Data;
END BuildingKinds.
